<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('lecturer');$page_title='Student Performance - SMIS';$lecturer=db_one('SELECT * FROM lecturers WHERE user_id=:id',['id'=>current_user()['id']]);$rows=db_all('SELECT u.name,s.student_number,c.name class_name,m.code,g.coursework,g.examination,g.final_grade,g.letter_grade,ROUND(100*SUM(a.status="present")/NULLIF(COUNT(a.id),0),1) attendance_rate FROM lecturer_modules lm JOIN students s ON s.class_id=lm.class_id JOIN users u ON u.id=s.user_id JOIN classes c ON c.id=s.class_id JOIN modules m ON m.id=lm.module_id JOIN student_modules sm ON sm.student_id=s.id AND sm.module_id=lm.module_id AND sm.semester_id=lm.semester_id LEFT JOIN grades g ON g.student_id=s.id AND g.module_id=lm.module_id LEFT JOIN attendance a ON a.student_id=s.id AND a.module_id=lm.module_id WHERE lm.lecturer_id=:id GROUP BY s.id,lm.module_id ORDER BY u.name,m.code',['id'=>$lecturer['id']]);include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Student Performance</h1><p>Grades and attendance for students in your assigned classes and modules.</p></div><div class="card"><div class="card-body"><table class="table"><thead><tr><th>Student</th><th>Class</th><th>Module</th><th>Coursework</th><th>Exam</th><th>Final</th><th>Grade</th><th>Attendance</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['name'])?></strong><br><small><?=e($r['student_number'])?></small></td><td><?=e($r['class_name'])?></td><td><?=e($r['code'])?></td><td><?=e($r['coursework']??'-')?></td><td><?=e($r['examination']??'-')?></td><td><?=e($r['final_grade']??'-')?></td><td><?=e($r['letter_grade']??'-')?></td><td><?=e($r['attendance_rate']??0)?>%</td></tr><?php endforeach?></tbody></table></div></div><?php include __DIR__.'/../includes/footer.php';?>
